-- ============================================================
-- TABLA 2: PMO_STAFF_SKILLS (150 técnicos)
-- Silos: Frontend, Soporte, Redes, Windows, Backend, QA, DevOps, Seguridad, BBDD
-- ============================================================
CREATE TABLE IF NOT EXISTS pmo_staff_skills (
    id_recurso VARCHAR(20) PRIMARY KEY,
    nombre TEXT NOT NULL,
    nivel VARCHAR(10) NOT NULL CHECK (nivel IN ('N1','N2','N3','N4')),
    silo_especialidad VARCHAR(50) NOT NULL CHECK (silo_especialidad IN (
        'Frontend','Soporte','Redes','Windows','Backend','QA','DevOps','Seguridad','BBDD'
    )),
    total_skills INTEGER DEFAULT 0,
    skills_json JSONB NOT NULL DEFAULT '[]'::jsonb,
    skill_principal VARCHAR(100),
    carga_actual INTEGER DEFAULT 0 CHECK (carga_actual >= 0 AND carga_actual <= 200),
    estado_run VARCHAR(20) DEFAULT 'DISPONIBLE' CHECK (estado_run IN (
        'DISPONIBLE','OCUPADO','GUARDIA','BAJA','VACACIONES'
    )),
    fecha_alta DATE DEFAULT CURRENT_DATE,
    fecha_ultima_asignacion TIMESTAMP,
    incidencias_resueltas INTEGER DEFAULT 0
);

CREATE INDEX idx_staff_nivel ON pmo_staff_skills(nivel);
CREATE INDEX idx_staff_silo ON pmo_staff_skills(silo_especialidad);
CREATE INDEX idx_staff_estado ON pmo_staff_skills(estado_run);
CREATE INDEX idx_staff_carga ON pmo_staff_skills(carga_actual);
CREATE INDEX idx_staff_skills_gin ON pmo_staff_skills USING GIN (skills_json);

