-- ============================================================
-- TABLA 4: CARTERA_BUILD (46 proyectos PMO)
-- ============================================================
CREATE TABLE IF NOT EXISTS cartera_build (
    id_proyecto VARCHAR(30) PRIMARY KEY,
    nombre_proyecto TEXT NOT NULL,
    prioridad_estrategica VARCHAR(20) NOT NULL CHECK (prioridad_estrategica IN ('Crítica','Alta','Media','Baja')),
    horas_estimadas INTEGER NOT NULL,
    skills_requeridas TEXT,
    horas_por_skill TEXT,
    estado VARCHAR(30) DEFAULT 'Standby' CHECK (estado IN (
        'Standby','En analisis','pendiente','en revision',
        'Aprobado','en ejecucion','en cierre','cerrado',
        'PAUSADO_POR_RIESGO_P1'
    )),
    perfil_requerido TEXT,
    responsable_asignado VARCHAR(20) REFERENCES pmo_staff_skills(id_recurso),
    horas_base INTEGER,
    fecha_creacion TIMESTAMP DEFAULT NOW(),
    fecha_ultima_modificacion TIMESTAMP DEFAULT NOW(),
    motivo_pausa TEXT,
    historial_estados JSONB DEFAULT '[]'::jsonb
);

CREATE INDEX idx_cartera_estado ON cartera_build(estado);
CREATE INDEX idx_cartera_prioridad ON cartera_build(prioridad_estrategica);
CREATE INDEX idx_cartera_responsable ON cartera_build(responsable_asignado);

