-- ============================================================
-- TABLA 5: INCIDENCIAS_RUN (operativa)
-- ============================================================
CREATE TABLE IF NOT EXISTS incidencias_run (
    ticket_id VARCHAR(30) PRIMARY KEY,
    incidencia_detectada TEXT NOT NULL,
    id_catalogo INTEGER REFERENCES catalogo_incidencias(id_catalogo),
    prioridad_ia VARCHAR(5) NOT NULL CHECK (prioridad_ia IN ('P1','P2','P3','P4')),
    categoria VARCHAR(100),
    estado VARCHAR(30) DEFAULT 'QUEUED' CHECK (estado IN (
        'QUEUED','EN_CURSO','ESCALADO','RESUELTO','CERRADO'
    )),
    sla_limite DECIMAL(5,1),
    tecnico_asignado VARCHAR(20) REFERENCES pmo_staff_skills(id_recurso),
    impacto_negocio TEXT,
    area_afectada TEXT,
    flag_reasignacion BOOLEAN DEFAULT FALSE,
    timestamp_creacion TIMESTAMP DEFAULT NOW(),
    timestamp_asignacion TIMESTAMP,
    timestamp_resolucion TIMESTAMP,
    tiempo_resolucion_minutos INTEGER,
    agente_origen VARCHAR(20) DEFAULT 'AG-001'
);

CREATE INDEX idx_inc_run_estado ON incidencias_run(estado);
CREATE INDEX idx_inc_run_prioridad ON incidencias_run(prioridad_ia);
CREATE INDEX idx_inc_run_tecnico ON incidencias_run(tecnico_asignado);
CREATE INDEX idx_inc_run_fecha ON incidencias_run(timestamp_creacion);

-- ============================================================
-- TABLA 6: GOBERNANZA_TRANSACCIONES (Auditoría)
-- ============================================================
CREATE SEQUENCE IF NOT EXISTS seq_txn START 1;

CREATE TABLE IF NOT EXISTS gobernanza_transacciones (
    id_transaccion VARCHAR(30) PRIMARY KEY,
    tipo_accion VARCHAR(30) NOT NULL CHECK (tipo_accion IN (
        'PAUSA_PROYECTO','REANUDACION_PROYECTO','ASIGNACION_RECURSO',
        'LIBERACION_RECURSO','FREEZE_PERIOD','CAMBIO_ESTADO','CREACION_PROYECTO'
    )),
    id_proyecto VARCHAR(30) REFERENCES cartera_build(id_proyecto),
    fte_afectado VARCHAR(20) REFERENCES pmo_staff_skills(id_recurso),
    estado_anterior VARCHAR(30),
    estado_nuevo VARCHAR(30),
    motivo TEXT,
    agente_origen VARCHAR(20) NOT NULL,
    datos_contexto JSONB DEFAULT '{}'::jsonb,
    timestamp_ejecucion TIMESTAMP DEFAULT NOW(),
    usuario_db VARCHAR(30) DEFAULT 'jose_admin'
);

CREATE INDEX idx_txn_tipo ON gobernanza_transacciones(tipo_accion);
CREATE INDEX idx_txn_proyecto ON gobernanza_transacciones(id_proyecto);
CREATE INDEX idx_txn_fte ON gobernanza_transacciones(fte_afectado);
CREATE INDEX idx_txn_fecha ON gobernanza_transacciones(timestamp_ejecucion);
CREATE INDEX idx_txn_agente ON gobernanza_transacciones(agente_origen);

-- ============================================================
-- VISTAS
-- ============================================================

CREATE OR REPLACE VIEW vista_carga_por_silo AS
SELECT silo_especialidad, nivel, COUNT(*) as total_tecnicos,
       ROUND(AVG(carga_actual), 1) as carga_media,
       SUM(CASE WHEN estado_run = 'DISPONIBLE' THEN 1 ELSE 0 END) as disponibles,
       SUM(CASE WHEN estado_run = 'OCUPADO' THEN 1 ELSE 0 END) as ocupados
FROM pmo_staff_skills
GROUP BY silo_especialidad, nivel
ORDER BY silo_especialidad, nivel;

CREATE OR REPLACE VIEW vista_portafolio_build AS
SELECT estado, prioridad_estrategica, COUNT(*) as total_proyectos,
       SUM(horas_estimadas) as horas_totales,
       COUNT(responsable_asignado) as con_responsable
FROM cartera_build
GROUP BY estado, prioridad_estrategica
ORDER BY prioridad_estrategica, estado;

CREATE OR REPLACE VIEW vista_proyectos_riesgo AS
SELECT id_proyecto, nombre_proyecto, prioridad_estrategica, estado,
       responsable_asignado, motivo_pausa
FROM cartera_build
WHERE estado = 'PAUSADO_POR_RIESGO_P1'
   OR (estado = 'en ejecucion' AND responsable_asignado IS NULL);

CREATE OR REPLACE VIEW view_disponibilidad_global AS
SELECT s.id_recurso, s.nombre, s.nivel, s.silo_especialidad,
       s.skill_principal, s.carga_actual, s.estado_run, s.skills_json, s.total_skills,
       COALESCE((SELECT COUNT(*) FROM incidencias_run i 
                 WHERE i.tecnico_asignado = s.id_recurso 
                 AND i.estado IN ('QUEUED','EN_CURSO')), 0) as incidencias_activas,
       COALESCE((SELECT COUNT(*) FROM cartera_build c 
                 WHERE c.responsable_asignado = s.id_recurso 
                 AND c.estado = 'en ejecucion'), 0) as proyectos_activos
FROM pmo_staff_skills s;

CREATE OR REPLACE VIEW vista_audit_gobernanza AS
SELECT g.id_transaccion, g.tipo_accion, g.timestamp_ejecucion, g.agente_origen,
       c.nombre_proyecto, c.prioridad_estrategica,
       s.nombre as nombre_tecnico, g.estado_anterior, g.estado_nuevo, g.motivo
FROM gobernanza_transacciones g
LEFT JOIN cartera_build c ON g.id_proyecto = c.id_proyecto
LEFT JOIN pmo_staff_skills s ON g.fte_afectado = s.id_recurso
ORDER BY g.timestamp_ejecucion DESC;

CREATE OR REPLACE VIEW vista_serie_temporal_incidencias AS
SELECT DATE(timestamp_creacion) as ds, COUNT(*) as y
FROM incidencias_run
GROUP BY DATE(timestamp_creacion)
ORDER BY ds;

-- ============================================================
-- FUNCIÓN: Buscar mejor técnico por skill
-- ============================================================
CREATE OR REPLACE FUNCTION buscar_tecnico_por_skill(
    p_skill TEXT, p_nivel_minimo TEXT DEFAULT 'N2'
) RETURNS TABLE (
    id_recurso VARCHAR, nombre TEXT, nivel VARCHAR,
    silo_especialidad VARCHAR, carga_actual INTEGER,
    estado_run VARCHAR, match_score INTEGER
) AS $$
BEGIN
    RETURN QUERY
    SELECT s.id_recurso, s.nombre, s.nivel, s.silo_especialidad,
           s.carga_actual, s.estado_run,
           (CASE WHEN s.skills_json @> to_jsonb(p_skill)::jsonb THEN 100 ELSE 0 END + 
            CASE s.nivel WHEN 'N4' THEN 40 WHEN 'N3' THEN 30 WHEN 'N2' THEN 20 WHEN 'N1' THEN 10 END -
            s.carga_actual) as match_score
    FROM pmo_staff_skills s
    WHERE s.estado_run = 'DISPONIBLE'
      AND s.nivel >= p_nivel_minimo
      AND s.skills_json @> to_jsonb(p_skill)::jsonb
    ORDER BY match_score DESC
    LIMIT 10;
END;
$$ LANGUAGE plpgsql;

-- ============================================================
-- TRIGGER: Historial automático de cambios de estado
-- ============================================================
CREATE OR REPLACE FUNCTION fn_registrar_cambio_estado()
RETURNS TRIGGER AS $$
BEGIN
    IF OLD.estado IS DISTINCT FROM NEW.estado THEN
        NEW.historial_estados = OLD.historial_estados || 
            jsonb_build_object(
                'estado_anterior', OLD.estado,
                'estado_nuevo', NEW.estado,
                'timestamp', NOW()::TEXT,
                'motivo', COALESCE(NEW.motivo_pausa, 'Cambio de estado')
            );
        NEW.fecha_ultima_modificacion = NOW();
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_cambio_estado_proyecto
    BEFORE UPDATE ON cartera_build
    FOR EACH ROW
    EXECUTE FUNCTION fn_registrar_cambio_estado();

-- ============================================================
-- TABLA 7: PRESUPUESTOS DE PROYECTOS (PMBOK 7)
-- ============================================================
CREATE TABLE IF NOT EXISTS presupuestos (
    id_presupuesto      VARCHAR(30) PRIMARY KEY,
    id_proyecto         VARCHAR(100) NOT NULL,
    nombre_presupuesto  VARCHAR(200) NOT NULL,
    version             INTEGER NOT NULL DEFAULT 1,
    estado              VARCHAR(20) NOT NULL DEFAULT 'BORRADOR'
                        CHECK (estado IN ('BORRADOR','EN_REVISION','APROBADO','CERRADO','RECHAZADO')),
    responsable         VARCHAR(100) NOT NULL,
    fecha_inicio        DATE,
    fecha_fin           DATE,
    moneda              VARCHAR(3) NOT NULL DEFAULT 'EUR',
    -- Coste de Personal Interno
    horas_internas      DECIMAL(10,2) NOT NULL DEFAULT 0,
    tarifa_hora_interna DECIMAL(10,2) NOT NULL DEFAULT 85.00,
    -- Proveedores Externos (JSON array de objetos)
    proveedores_externos JSONB NOT NULL DEFAULT '[]',
    -- OPEX — Gastos Operacionales
    opex_licencias_sw   DECIMAL(12,2) NOT NULL DEFAULT 0,
    opex_cloud_infra    DECIMAL(12,2) NOT NULL DEFAULT 0,
    opex_mantenimiento  DECIMAL(12,2) NOT NULL DEFAULT 0,
    opex_consumibles    DECIMAL(12,2) NOT NULL DEFAULT 0,
    opex_formacion      DECIMAL(12,2) NOT NULL DEFAULT 0,
    opex_otros          DECIMAL(12,2) NOT NULL DEFAULT 0,
    -- CAPEX — Inversiones de Capital
    capex_hardware      DECIMAL(12,2) NOT NULL DEFAULT 0,
    capex_equipamiento  DECIMAL(12,2) NOT NULL DEFAULT 0,
    capex_infraestructura DECIMAL(12,2) NOT NULL DEFAULT 0,
    capex_software      DECIMAL(12,2) NOT NULL DEFAULT 0,
    capex_otros         DECIMAL(12,2) NOT NULL DEFAULT 0,
    -- Gestión de Personal / RRHH
    rrhh_reclutamiento  DECIMAL(12,2) NOT NULL DEFAULT 0,
    rrhh_formacion      DECIMAL(12,2) NOT NULL DEFAULT 0,
    rrhh_hr_admin       DECIMAL(12,2) NOT NULL DEFAULT 0,
    rrhh_viajes_dietas  DECIMAL(12,2) NOT NULL DEFAULT 0,
    rrhh_otros          DECIMAL(12,2) NOT NULL DEFAULT 0,
    -- Reservas PMBOK 7
    reserva_contingencia_pct DECIMAL(5,2) NOT NULL DEFAULT 10.0,
    reserva_gestion_pct      DECIMAL(5,2) NOT NULL DEFAULT 5.0,
    -- Totales calculados (desnormalizados para rendimiento)
    total_labor         DECIMAL(12,2) NOT NULL DEFAULT 0,
    total_proveedores   DECIMAL(12,2) NOT NULL DEFAULT 0,
    total_opex          DECIMAL(12,2) NOT NULL DEFAULT 0,
    total_capex         DECIMAL(12,2) NOT NULL DEFAULT 0,
    total_rrhh          DECIMAL(12,2) NOT NULL DEFAULT 0,
    total_reservas      DECIMAL(12,2) NOT NULL DEFAULT 0,
    bac_total           DECIMAL(12,2) NOT NULL DEFAULT 0,
    -- Aprobación formal
    aprobado_por        VARCHAR(100),
    fecha_aprobacion    DATE,
    notas               TEXT,
    created_at          TIMESTAMP DEFAULT NOW(),
    updated_at          TIMESTAMP DEFAULT NOW()
);

CREATE INDEX idx_pres_proyecto  ON presupuestos(id_proyecto);
CREATE INDEX idx_pres_estado    ON presupuestos(estado);
CREATE INDEX idx_pres_responsable ON presupuestos(responsable);

-- ============================================================
-- TABLA 8: WAR ROOM — CONVERSACIONES DE AGENTES IA
-- ============================================================
CREATE TABLE IF NOT EXISTS agent_conversations (
    id              VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    session_id      VARCHAR(50) NOT NULL DEFAULT gen_random_uuid()::text,
    agent_id        VARCHAR(10) NOT NULL,
    agent_name      VARCHAR(100) NOT NULL,
    role            VARCHAR(20) NOT NULL CHECK (role IN ('user','assistant','system','tool')),
    content         TEXT NOT NULL,
    tokens_used     INTEGER DEFAULT 0,
    model_used      VARCHAR(50) DEFAULT 'claude-sonnet-4-20250514',
    latency_ms      INTEGER DEFAULT 0,
    metadata        JSONB DEFAULT '{}',
    created_at      TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_conv_session ON agent_conversations(session_id);
CREATE INDEX IF NOT EXISTS idx_conv_agent ON agent_conversations(agent_id);
CREATE INDEX IF NOT EXISTS idx_conv_created ON agent_conversations(created_at DESC);

-- ============================================================
-- TABLA 9: WAR ROOM — AUDITORÍAS DE COMPLIANCE
-- ============================================================
CREATE TABLE IF NOT EXISTS compliance_audits (
    id              VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    audit_type      VARCHAR(50) NOT NULL CHECK (audit_type IN (
                        'ITIL4_SLA','PMBOK7_DELIVERABLE','GDPR_DATA','BCE_REGULATORY',
                        'ISO27001_SECURITY','CNMV_REPORTING','DORA_RESILIENCE')),
    entity_type     VARCHAR(30) NOT NULL,
    entity_id       VARCHAR(100) NOT NULL,
    severity        VARCHAR(10) NOT NULL CHECK (severity IN ('CRITICAL','HIGH','MEDIUM','LOW','INFO')),
    finding         TEXT NOT NULL,
    recommendation  TEXT,
    evidence        JSONB DEFAULT '{}',
    status          VARCHAR(20) DEFAULT 'OPEN' CHECK (status IN ('OPEN','IN_PROGRESS','RESOLVED','ACCEPTED','WAIVED')),
    assignee        VARCHAR(100),
    due_date        DATE,
    resolved_at     TIMESTAMPTZ,
    created_by      VARCHAR(20) DEFAULT 'AG-008',
    created_at      TIMESTAMPTZ DEFAULT NOW(),
    updated_at      TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_audit_type ON compliance_audits(audit_type);
CREATE INDEX IF NOT EXISTS idx_audit_severity ON compliance_audits(severity);
CREATE INDEX IF NOT EXISTS idx_audit_status ON compliance_audits(status);

-- ============================================================
-- TABLA 10: WAR ROOM — INFORMES POST-MORTEM
-- ============================================================
CREATE TABLE IF NOT EXISTS postmortem_reports (
    id                  VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    incident_id         VARCHAR(50) NOT NULL,
    incident_priority   VARCHAR(5) NOT NULL,
    title               VARCHAR(300) NOT NULL,
    timeline            JSONB NOT NULL DEFAULT '[]',
    root_cause          TEXT NOT NULL,
    root_cause_category VARCHAR(50),
    impact_assessment   JSONB NOT NULL DEFAULT '{}',
    corrective_actions  JSONB NOT NULL DEFAULT '[]',
    preventive_actions  JSONB NOT NULL DEFAULT '[]',
    lessons_learned     TEXT[] DEFAULT '{}',
    mttr_minutes        INTEGER,
    mtta_minutes        INTEGER,
    sla_breached        BOOLEAN DEFAULT FALSE,
    agents_involved     VARCHAR(10)[] DEFAULT '{}',
    resources_involved  VARCHAR(20)[] DEFAULT '{}',
    projects_impacted   VARCHAR(50)[] DEFAULT '{}',
    review_status       VARCHAR(20) DEFAULT 'DRAFT' CHECK (review_status IN ('DRAFT','REVIEW','APPROVED','ARCHIVED')),
    approved_by         VARCHAR(100),
    created_at          TIMESTAMPTZ DEFAULT NOW(),
    updated_at          TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_pm_incident ON postmortem_reports(incident_id);
CREATE INDEX IF NOT EXISTS idx_pm_priority ON postmortem_reports(incident_priority);

-- ============================================================
-- TABLA 11: WAR ROOM — SIMULACIONES WHAT-IF
-- ============================================================
CREATE TABLE IF NOT EXISTS whatif_simulations (
    id                  VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    simulation_name     VARCHAR(200) NOT NULL,
    scenario_type       VARCHAR(50) NOT NULL CHECK (scenario_type IN (
                            'RESOURCE_REALLOCATION','PROJECT_DELAY','P1_CASCADE',
                            'BUDGET_CUT','TEAM_SCALING','FREEZE_PERIOD',
                            'SKILL_GAP','VENDOR_FAILURE','REGULATORY_CHANGE')),
    input_params        JSONB NOT NULL DEFAULT '{}',
    baseline_snapshot   JSONB NOT NULL DEFAULT '{}',
    simulation_result   JSONB NOT NULL DEFAULT '{}',
    risk_score          DECIMAL(5,2) DEFAULT 0 CHECK (risk_score BETWEEN 0 AND 100),
    confidence_level    DECIMAL(3,2) DEFAULT 0.7 CHECK (confidence_level BETWEEN 0 AND 1),
    recommendations     TEXT[] DEFAULT '{}',
    affected_projects   VARCHAR(50)[] DEFAULT '{}',
    affected_resources  VARCHAR(20)[] DEFAULT '{}',
    kpi_deltas          JSONB DEFAULT '{}',
    created_by          VARCHAR(100) DEFAULT 'AG-010',
    created_at          TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_sim_type ON whatif_simulations(scenario_type);
CREATE INDEX IF NOT EXISTS idx_sim_risk ON whatif_simulations(risk_score DESC);

-- ============================================================
-- TABLA 12: WAR ROOM — ALERTAS INTELIGENTES
-- ============================================================
CREATE TABLE IF NOT EXISTS intelligent_alerts (
    id                  VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    alert_type          VARCHAR(50) NOT NULL CHECK (alert_type IN (
                            'SLA_RISK','OVERALLOCATION','SKILL_GAP','FREEZE_RECOMMENDED',
                            'BUDGET_OVERRUN','MILESTONE_RISK','BURNOUT_RISK',
                            'COMPLIANCE_BREACH','CASCADE_FAILURE','CAPACITY_THRESHOLD')),
    severity            VARCHAR(10) NOT NULL CHECK (severity IN ('CRITICAL','HIGH','MEDIUM','LOW')),
    title               VARCHAR(300) NOT NULL,
    description         TEXT NOT NULL,
    source_agent        VARCHAR(10) NOT NULL,
    affected_entities   JSONB NOT NULL DEFAULT '{}',
    trigger_condition   JSONB NOT NULL DEFAULT '{}',
    recommended_actions JSONB DEFAULT '[]',
    auto_resolved       BOOLEAN DEFAULT FALSE,
    acknowledged_by     VARCHAR(100),
    acknowledged_at     TIMESTAMPTZ,
    resolved_at         TIMESTAMPTZ,
    status              VARCHAR(20) DEFAULT 'ACTIVE' CHECK (status IN ('ACTIVE','ACKNOWLEDGED','RESOLVED','ESCALATED','SUPPRESSED')),
    correlation_id      VARCHAR(50),
    parent_alert_id     VARCHAR(50),
    ttl_hours           INTEGER DEFAULT 24,
    created_at          TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_alert_type ON intelligent_alerts(alert_type);
CREATE INDEX IF NOT EXISTS idx_alert_severity ON intelligent_alerts(severity);
CREATE INDEX IF NOT EXISTS idx_alert_status ON intelligent_alerts(status);
CREATE INDEX IF NOT EXISTS idx_alert_source ON intelligent_alerts(source_agent);

-- ============================================================
-- TABLA 13: WAR ROOM — SESIONES WAR ROOM
-- ============================================================
CREATE TABLE IF NOT EXISTS war_room_sessions (
    id              VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    session_name    VARCHAR(200) NOT NULL,
    session_type    VARCHAR(30) NOT NULL CHECK (session_type IN (
                        'CRISIS_P1','PLANNING','REVIEW','SIMULATION','AUDIT','AD_HOC')),
    status          VARCHAR(20) DEFAULT 'ACTIVE' CHECK (status IN ('ACTIVE','PAUSED','CLOSED','ARCHIVED')),
    participants    JSONB DEFAULT '[]',
    context         JSONB DEFAULT '{}',
    summary         TEXT,
    decisions       JSONB DEFAULT '[]',
    started_at      TIMESTAMPTZ DEFAULT NOW(),
    closed_at       TIMESTAMPTZ
);
CREATE INDEX IF NOT EXISTS idx_wr_status ON war_room_sessions(status);
CREATE INDEX IF NOT EXISTS idx_wr_type ON war_room_sessions(session_type);

-- ============================================================
-- TABLA 14: WAR ROOM — MÉTRICAS DE RENDIMIENTO DE AGENTES
-- ============================================================
CREATE TABLE IF NOT EXISTS agent_performance_metrics (
    id                      VARCHAR(50) PRIMARY KEY DEFAULT gen_random_uuid()::text,
    agent_id                VARCHAR(10) NOT NULL,
    metric_date             DATE NOT NULL DEFAULT CURRENT_DATE,
    total_invocations       INTEGER DEFAULT 0,
    avg_latency_ms          DECIMAL(10,2) DEFAULT 0,
    total_tokens_consumed   BIGINT DEFAULT 0,
    success_rate            DECIMAL(5,2) DEFAULT 100.00,
    error_count             INTEGER DEFAULT 0,
    decisions_made          INTEGER DEFAULT 0,
    escalations_triggered   INTEGER DEFAULT 0,
    created_at              TIMESTAMPTZ DEFAULT NOW(),
    UNIQUE(agent_id, metric_date)
);

-- ============================================================
-- TABLA 15: KANBAN — TAREAS CON FLUJO DE TRABAJO
-- ============================================================
CREATE TABLE IF NOT EXISTS kanban_tareas (
    id              VARCHAR(30) PRIMARY KEY,
    titulo          TEXT NOT NULL,
    descripcion     TEXT,
    tipo            VARCHAR(10) NOT NULL CHECK (tipo IN ('RUN','BUILD')),
    prioridad       VARCHAR(10) NOT NULL CHECK (prioridad IN ('Crítica','Alta','Media','Baja')),
    columna         VARCHAR(30) NOT NULL DEFAULT 'Backlog' CHECK (columna IN (
                        'Backlog','Análisis','En Progreso','Code Review','Testing','Despliegue','Bloqueado','Completado')),
    id_tecnico      VARCHAR(20) REFERENCES pmo_staff_skills(id_recurso),
    id_proyecto     VARCHAR(30),
    id_incidencia   VARCHAR(30),
    bloqueador      TEXT,
    horas_estimadas DECIMAL(6,1) DEFAULT 0,
    horas_reales    DECIMAL(6,1) DEFAULT 0,
    fecha_creacion      TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    fecha_inicio_ejecucion TIMESTAMPTZ,
    fecha_cierre        TIMESTAMPTZ,
    historial_columnas  JSONB DEFAULT '[]',
    created_at      TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_kanban_columna ON kanban_tareas(columna);
CREATE INDEX IF NOT EXISTS idx_kanban_tipo ON kanban_tareas(tipo);
CREATE INDEX IF NOT EXISTS idx_kanban_tecnico ON kanban_tareas(id_tecnico);
CREATE INDEX IF NOT EXISTS idx_kanban_proyecto ON kanban_tareas(id_proyecto);
CREATE INDEX IF NOT EXISTS idx_kanban_incidencia ON kanban_tareas(id_incidencia);

-- ============================================================
-- VERIFICACIÓN FINAL
-- ============================================================
SELECT 'catalogo_skills' as tabla, COUNT(*) as registros FROM catalogo_skills
UNION ALL SELECT 'pmo_staff_skills', COUNT(*) FROM pmo_staff_skills
UNION ALL SELECT 'catalogo_incidencias', COUNT(*) FROM catalogo_incidencias
UNION ALL SELECT 'cartera_build', COUNT(*) FROM cartera_build
UNION ALL SELECT 'incidencias_run', COUNT(*) FROM incidencias_run
UNION ALL SELECT 'gobernanza_transacciones', COUNT(*) FROM gobernanza_transacciones
UNION ALL SELECT 'agent_conversations', COUNT(*) FROM agent_conversations
UNION ALL SELECT 'compliance_audits', COUNT(*) FROM compliance_audits
UNION ALL SELECT 'postmortem_reports', COUNT(*) FROM postmortem_reports
UNION ALL SELECT 'whatif_simulations', COUNT(*) FROM whatif_simulations
UNION ALL SELECT 'intelligent_alerts', COUNT(*) FROM intelligent_alerts
UNION ALL SELECT 'war_room_sessions', COUNT(*) FROM war_room_sessions
UNION ALL SELECT 'agent_performance_metrics', COUNT(*) FROM agent_performance_metrics
UNION ALL SELECT 'kanban_tareas', COUNT(*) FROM kanban_tareas;

-- Verificar distribución por silo
SELECT silo_especialidad, COUNT(*) as tecnicos, 
       STRING_AGG(DISTINCT nivel, ', ' ORDER BY nivel) as niveles
FROM pmo_staff_skills 
GROUP BY silo_especialidad 
ORDER BY silo_especialidad;